                Version = "2.0",
                IssueInstant = DateTime.UtcNow,
                ProtocolBinding = "urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST",
                AssertionConsumerServiceUrl = new Uri("https://example.com/assertion_consumer_service"),
            };
            
        request.RequestedAuthenticationContexts.Add(new RequestedAuthnContext 
        {
            Comparison = AuthnContextComparisonType.Exact,
            ClassReference = "urn:oasis:names:tc:SAML:2.0:ac:classes:PasswordProtectedTransport",
        });
            
        // Sign the request with RSA-SHA1 signature and set it to the request
        var rsaCryptoServiceProvider = new RSACryptoServiceProvider();
        rsaCryptoServiceProvider.ImportParameters(RsaParameters);
        
        var xmlSignature = new XmlDsigExcC14NTransform();
        var signatureDescription = new RSAKeyValue((RSA)rsaCryptoServiceProvider);
        request.AddSignableObjectList(new SignableObjects() { ObjectToSign = request, SignatureType = "http://www.w3.org/2001/04/xmldsig-more#rsa-sha1", KeyInfo = signatureDescription });
        
        var writer = new XmlTextWriter(new System.IO.StringWriter());
        request.WriteSamlMessage(writer);
            
        return ((System.IO.StringWriter)writer.UnderlyingWriter).ToString(); 
